var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LAURA_STREGA_ReinforcedA_NULL`,text:{KOREA:`왜 불렀는지 알고 있냐고? 글쎄.`,JPN:`どうして呼んだかわかるかだと？　さあ、どうだろうな。`,ENG:`Do I know why you called me? I don't know.`,TWN:`你問我知不知道自己為什麼會被叫來？誰知道呢？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_ReinforcedA_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LAURA_STREGA_ReinforcedA_NULL`,text:{KOREA:`회사에 우리 스트레가 카페의 2호점을 내고 싶다거나......?`,JPN:`妾のストレガカフェ2号店を会社に出店させたいとか、そんなところか……？`,ENG:`Maybe you want to open a second Cafe Strega location in your building?`,TWN:`是想在公司開史特雷加咖啡廳的2號店……？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_ReinforcedA_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LAURA_STREGA_ReinforcedA_NULL`,text:{KOREA:`......농담이야. 난 마녀지, 독심술사나 사이코매트리가 아니니까.`,JPN:`……今のはジョークだ。妾は魔女であって、読心術師でもサイコメトラーでもないぞ。`,ENG:`I was just kidding. I'm a witch, not a mind reader or psychic.`,TWN:`……開玩笑的。畢竟我是魔女嘛，又不是讀心術專家或有心電感應。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_ReinforcedA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LAURA_STREGA_ReinforcedA_NULL`,text:{KOREA:`응? 나와 종신계약을 하고 싶어?`,JPN:`なに？　妾と終身契約を結びたいだと？`,ENG:`Huh? You want to hire me for life?`,TWN:`嗯？你想跟我簽終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_ReinforcedA_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LAURA_STREGA_ReinforcedA_NULL`,text:{KOREA:`뭐, 좋아. 못할 것도 없지.`,JPN:`まあ、よかろう。好きにするがいいさ。`,ENG:`Well, sure. Why not?`,TWN:`嗯，好啊，有什麼不好的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_ReinforcedA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LAURA_STREGA_ReinforcedA_NULL`,text:{KOREA:`대신 약속을 어기면 끔찍한 사고를 겪는 저주를 걸어두겠어.`,JPN:`ただし、約束を違えれば恐ろしい事故に遭ってしまう呪いをかけておこう。`,ENG:`But you'd better not betray me, or I'll put a terrible curse on you.`,TWN:`不過萬一你打破了約定，我就會詛咒你遇到可怕的意外。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_ReinforcedA_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LAURA_STREGA_ReinforcedA_NULL`,text:{KOREA:`후후...... 꽤 길들이는 보람이 있겠는걸.`,JPN:`ふふ……しつけのし甲斐がありそうだ。`,ENG:`Hah hah. It's going to be fun taming you!`,TWN:`呵呵……你應該很有馴服的價值。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LAURA_STREGA_ReinforcedA_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};